// ─── Wire Format ──────────────────────────────────────────────────────
//
// Each record: [record_len:u32]
//   [id_len:u16][id]
//   [item_type:u8]
//   [dep_count:u16][dep_len:u16][dep]...
//   [content_len:u32][content]
//   [receipt_hash:32]
//   [locked_at_k:u64]
//   [has_supersedes:u8][supersedes_len:u16][supersedes]

fn encode_item(item: &RegisterItem) -> Vec<u8> {
    let id_bytes = item.id.as_bytes();
    let sup_bytes = item.supersedes.as_deref().unwrap_or("").as_bytes();

    // Calculate deps size
    let deps_size: usize = item.depends_on.iter()
        .map(|d| 2 + d.as_bytes().len())
        .sum::<usize>() + 2; // +2 for dep_count

    let body_len = 2 + id_bytes.len()       // id_len + id
        + 1                                  // item_type
        + deps_size                          // dep_count + deps
        + 4 + item.content.len()             // content_len + content
        + 32                                 // receipt_hash
        + 8                                  // locked_at_k
        + 1                                  // has_supersedes
        + 2 + sup_bytes.len();               // supersedes_len + supersedes

    let mut buf = Vec::with_capacity(4 + body_len);

    // Record length prefix
    buf.extend_from_slice(&(body_len as u32).to_be_bytes());

    // id
    buf.extend_from_slice(&(id_bytes.len() as u16).to_be_bytes());
    buf.extend_from_slice(id_bytes);

    // item_type
    buf.push(item.item_type as u8);

    // depends_on
    buf.extend_from_slice(&(item.depends_on.len() as u16).to_be_bytes());
    for dep in &item.depends_on {
        let db = dep.as_bytes();
        buf.extend_from_slice(&(db.len() as u16).to_be_bytes());
        buf.extend_from_slice(db);
    }

    // content
    buf.extend_from_slice(&(item.content.len() as u32).to_be_bytes());
    buf.extend_from_slice(&item.content);

    // receipt_hash
    buf.extend_from_slice(&item.receipt_hash);

    // locked_at_k
    buf.extend_from_slice(&item.locked_at_k.to_be_bytes());

    // supersedes
    buf.push(if item.supersedes.is_some() { 1 } else { 0 });
    buf.extend_from_slice(&(sup_bytes.len() as u16).to_be_bytes());
    buf.extend_from_slice(sup_bytes);

    buf
}

fn decode_item(data: &[u8]) -> Option<RegisterItem> {
    let mut off = 0;

    // id
    if data.len() < off + 2 { return None; }
    let id_len = u16::from_be_bytes(data[off..off + 2].try_into().ok()?) as usize;
    off += 2;
    if off + id_len > data.len() { return None; }
    let id = std::str::from_utf8(&data[off..off + id_len]).ok()?.to_string();
    off += id_len;

    // item_type
    if off + 1 > data.len() { return None; }
    let item_type = RegisterType::from_u8(data[off])?;
    off += 1;

    // depends_on
    if off + 2 > data.len() { return None; }
    let dep_count = u16::from_be_bytes(data[off..off + 2].try_into().ok()?) as usize;
    off += 2;
    let mut depends_on = Vec::with_capacity(dep_count);
    for _ in 0..dep_count {
        if off + 2 > data.len() { return None; }
        let dep_len = u16::from_be_bytes(data[off..off + 2].try_into().ok()?) as usize;
        off += 2;
        if off + dep_len > data.len() { return None; }
        depends_on.push(std::str::from_utf8(&data[off..off + dep_len]).ok()?.to_string());
        off += dep_len;
    }

    // content
    if off + 4 > data.len() { return None; }
    let content_len = u32::from_be_bytes(data[off..off + 4].try_into().ok()?) as usize;
    off += 4;
    if off + content_len > data.len() { return None; }
    let content = data[off..off + content_len].to_vec();
    off += content_len;

    // receipt_hash
    if off + 32 > data.len() { return None; }
    let mut receipt_hash = [0u8; 32];
    receipt_hash.copy_from_slice(&data[off..off + 32]);
    off += 32;

    // locked_at_k
    if off + 8 > data.len() { return None; }
    let locked_at_k = u64::from_be_bytes(data[off..off + 8].try_into().ok()?);
    off += 8;

    // supersedes
    if off + 1 > data.len() { return None; }
    let has_sup = data[off] != 0;
    off += 1;

    if off + 2 > data.len() { return None; }
    let sup_len = u16::from_be_bytes(data[off..off + 2].try_into().ok()?) as usize;
    off += 2;

    let supersedes = if has_sup && sup_len > 0 && off + sup_len <= data.len() {
        Some(std::str::from_utf8(&data[off..off + sup_len]).ok()?.to_string())
    } else {
        None
    };

    Some(RegisterItem { id, item_type, depends_on, content, receipt_hash, locked_at_k, supersedes, state: RegisterState::Locked, confirmations: vec![] })
}

// ─── Register Store ───────────────────────────────────────────────────

/// Persistent register store. Backed by register.bin.
/// In-memory HashMap for O(1) query, binary file for persistence.
pub struct Register {
    items: HashMap<String, RegisterItem>,
    file: File,
    path: PathBuf,
}

impl Register {
    /// Open or create the register store.
    pub fn open(path: &Path) -> io::Result<Self> {
        let file = OpenOptions::new()
            .read(true).write(true).create(true)
            .open(path)?;

        let mut items = HashMap::new();
        let metadata = file.metadata()?;
        if metadata.len() > 0 {
            let mut reader = io::BufReader::new(&file);
            loop {
                let mut len_buf = [0u8; 4];
                match reader.read_exact(&mut len_buf) {
                    Ok(()) => {},
                    Err(e) if e.kind() == io::ErrorKind::UnexpectedEof => break,
                    Err(e) => return Err(e),
                }
                let record_len = u32::from_be_bytes(len_buf) as usize;
                let mut record = vec![0u8; record_len];
                reader.read_exact(&mut record)?;
                if let Some(item) = decode_item(&record) {
                    items.insert(item.id.clone(), item);
                }
            }
        }

        Ok(Self { items, file, path: path.to_path_buf() })
    }

    /// Lock a register item. Returns the receipt hash.
    /// Rejects items with invalid hashes.
    pub fn lock(&mut self, item: RegisterItem) -> io::Result<[u8; 32]> {
        if !item.verify() {
            return Err(io::Error::new(io::ErrorKind::InvalidData, "receipt hash mismatch"));
        }

        let hash = item.receipt_hash;
        let encoded = encode_item(&item);
        self.file.seek(SeekFrom::End(0))?;
        self.file.write_all(&encoded)?;
        self.file.flush()?;
        self.items.insert(item.id.clone(), item);
        Ok(hash)
    }

    /// Query a register item by ID.
    pub fn query(&self, id: &str) -> Option<&RegisterItem> {
        self.items.get(id)
    }

    /// List all register items.
    pub fn list(&self) -> Vec<&RegisterItem> {
        let mut items: Vec<_> = self.items.values().collect();
        items.sort_by_key(|i| &i.id);
        items
    }

    /// Number of items in the register.
    pub fn len(&self) -> usize {
        self.items.len()
    }

    /// Whether the register is empty.
    pub fn is_empty(&self) -> bool {
        self.items.is_empty()
    }

    /// File path of the register store.
    pub fn path(&self) -> &Path {
        &self.path
    }

    /// Nominate a new crystallized truth for cross-orbital confirmation.
    ///
    /// The nomination enters the register in Nominated state with the
    /// nominating orbit as the first confirmation. It needs N confirmations
    /// from different orbits before crystallizing into Locked state.
    pub fn nominate(&mut self, mut item: RegisterItem, nominator_orbit: [u8; 4]) -> io::Result<()> {
        item.state = RegisterState::Nominated;
        item.confirmations = vec![nominator_orbit];
        self.items.insert(item.id.clone(), item);
        Ok(())
    }

    /// Confirm a nominated item from a different orbit.
    ///
    /// Returns true if this confirmation caused crystallization (state → Locked).
    /// The crystallization threshold is 3 confirmations from different orbits.
    pub fn confirm(&mut self, id: &str, confirming_orbit: [u8; 4]) -> Option<bool> {
        let item = self.items.get_mut(id)?;
        if item.state != RegisterState::Nominated { return Some(false); }

        // Only count new orbits — same orbit confirming twice doesn't count
        if !item.confirmations.contains(&confirming_orbit) {
            item.confirmations.push(confirming_orbit);
        }

        // Crystallization threshold: 3 confirmations from different orbits
        const CRYSTALLIZATION_THRESHOLD: usize = 3;
        if item.confirmations.len() >= CRYSTALLIZATION_THRESHOLD {
            item.state = RegisterState::Locked;
            // Persist the crystallized item
            let encoded = encode_item(item);
            let _ = self.file.seek(SeekFrom::End(0));
            let _ = self.file.write_all(&encoded);
            let _ = self.file.flush();
            return Some(true);
        }
        Some(false)
    }

    /// Query all nominated (not yet crystallized) items.
    pub fn nominations(&self) -> Vec<&RegisterItem> {
        self.items.values()
            .filter(|i| i.state == RegisterState::Nominated)
            .collect()
    }

    /// Query all crystallized items (mesh-discovered, now locked).
    pub fn crystallized(&self) -> Vec<&RegisterItem> {
        self.items.values()
            .filter(|i| i.item_type == RegisterType::Crystallized && i.state == RegisterState::Locked)
            .collect()
    }
}

